// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ContractSupplier) predicate.ContractSupplier {
	return predicate.ContractSupplier(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ContractSupplier) predicate.ContractSupplier {
	return predicate.ContractSupplier(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ContractSupplier) predicate.ContractSupplier {
	return predicate.ContractSupplier(sql.NotPredicates(p))
}
